export function sendEmergencyAlert(userMessage) {
  const emergencyContact = {
    name: "Emergency Contact",
    phone: "+91XXXXXXXXXX", // alternate number
    email: "emergency@example.com"
  };

  const alertPayload = {
    time: new Date().toLocaleString(),
    message: userMessage,
    status: "HIGH RISK",
  };

  console.log("🚨 EMERGENCY ALERT SENT", {
    to: emergencyContact,
    data: alertPayload,
  });

  // 🔐 FUTURE (Backend)
  // fetch("/api/send-alert", { method: "POST", body: JSON.stringify(alertPayload) });

  return true;
}
